-- =============================================================================
-- myBJJ V1 — SEED (Phase 3a)
-- Generated from index.html UNITS / STAFF / STUDENTS / PROMOTION_LOG /
-- EVENTS / SCHED. Run AFTER 04_schema_v2.sql. Safe to re-run (UPSERT).
-- =============================================================================

-- Counts: units=15 staff=3 students=52 promotions=7 events=5 sched=4

-- 1) Units
on conflict (legacy_id) do update set
  name=excluded.name, country=excluded.country, city=excluded.city,
  address=excluded.address, active=excluded.active;

-- 2) Staff (depends on units)
on conflict (legacy_id) do update set
  full_name=excluded.full_name, belt=excluded.belt, degree=excluded.degree,
  role_title=excluded.role_title, initials=excluded.initials,
  total_classes=excluded.total_classes, journey=excluded.journey,
  feedback=excluded.feedback, unit_id=excluded.unit_id;

-- 3) Students (depends on units)
on conflict (legacy_id) do update set
  full_name=excluded.full_name, belt=excluded.belt, degree=excluded.degree,
  prog=excluded.prog, total=excluded.total, gi_classes=excluded.gi_classes,
  nogi_classes=excluded.nogi_classes, grade=excluded.grade, gi_grade=excluded.gi_grade,
  initials=excluded.initials, has_gi=excluded.has_gi, gender=excluded.gender,
  journey=excluded.journey, feedback=excluded.feedback, unit_id=excluded.unit_id;

-- 4) Promotions (depends on students + units)
on conflict (legacy_id) do update set
  student_id=excluded.student_id, from_belt=excluded.from_belt,
  to_belt=excluded.to_belt, from_deg=excluded.from_deg, to_deg=excluded.to_deg,
  type=excluded.type, is_new_belt=excluded.is_new_belt, date=excluded.date,
  student_name=excluded.student_name, promoted_by_name=excluded.promoted_by_name,
  unit_id=excluded.unit_id;

-- 5) Events (depends on nothing — legacy_id arrays only)
on conflict (legacy_id) do update set
  title=excluded.title, date=excluded.date, date_text=excluded.date_text,
  type=excluded.type, description=excluded.description, link=excluded.link,
  competing_legacy_ids=excluded.competing_legacy_ids,
  supporting_legacy_ids=excluded.supporting_legacy_ids,
  unit_legacy_ids=excluded.unit_legacy_ids;

-- 6) Programme weeks (depends on units)
on conflict (legacy_id) do update set
  week_start=excluded.week_start, week_index=excluded.week_index,
  theme=excluded.theme, color=excluded.color, programs=excluded.programs,
  stand_up=excluded.stand_up, ground=excluded.ground, notes=excluded.notes,
  unit_id=excluded.unit_id;

